tag.map:
function (doc) {
  if (!doc.we_d && doc.we_tags && doc.we_tags.length > 0) {
    for (var i in doc.we_tags) {
      emit(doc.we_tags[i], doc.we_timestamp);
    }
  } else if (!doc.we_d && doc.we_tag && doc.we_timestamp) {
    emit(doc.we_tag, doc.we_timestamp);
  }
}

missing_weavatars.map:
function(doc) {
  if (doc.we_source && doc.we_source === 'wikieducator' && doc.profile_image_url === '') {
    emit(doc.from_user, null);
  }
}

time.map:
function (doc) {
  if (doc.we_timestamp && !doc.we_d) {
    if (doc.we_tags && doc.we_tags.length > 0) {
      for(var i in doc.we_tags) {
        emit(doc.we_timestamp, doc.we_tags[i]);
      }
    } else if (doc.we_tag) {
        emit(doc.we_timestamp, doc.we_tag);
    }
  }
}

google.map:
function (doc) {
  if (doc.we_source === "g+" && doc.we_timestamp) {
    if (doc.we_tags && doc.we_tags.length > 1) {
      for(var i in doc.we_tags) {
        emit([doc.we_tags[i], doc.we_timestamp], null);
      }
    } else if (doc.we_tag) {
      emit([doc.we_tag, doc.we_timestamp], null);
    }
  }
}

